// // This module implements a 1-bit synchronous D flip-flop with enable. The D flip-flop captures the value of d on each negative edge of the clock signal clk when the enable signal en is low. When the reset signal rst_n is high, the flip-flop resets to one.
module dff_en(
    input clk,
    input rst_n,
    input en,
    input d,
    output reg q
);
    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            q <= 1'b0;
        end else if (en) begin
            q <= d;
        end
    end
endmodule
